import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { toast } from 'react-toastify';
import jsPDF from 'jspdf';
import 'jspdf-autotable';

const Reports = () => {
  const [loading, setLoading] = useState(true);
  const [savings, setSavings] = useState(null);
  const [loans, setLoans] = useState([]);
  const [repayments, setRepayments] = useState(null);
  const [selectedSections, setSelectedSections] = useState({
    summary: true,
    loans: true,
    savings: true,
    repayments: true
  });

  useEffect(() => {
    fetchReports();
  }, []);

  const fetchReports = async () => {
    try {
      setLoading(true);
      const [savingsRes, loansRes, repaymentsRes] = await Promise.all([
        api.get('/admin/reports/savings'),
        api.get('/admin/reports/loans'),
        api.get('/admin/reports/repayments')
      ]);

      // Handle wrapped responses - backend uses success(res, data) which wraps in { data: {...} }
      setSavings(savingsRes.data?.data || savingsRes.data || { total: 0, count: 0 });

      // Loans response is an array
      const loansData = loansRes.data?.data || loansRes.data || [];
      setLoans(Array.isArray(loansData) ? loansData : []);

      setRepayments(repaymentsRes.data?.data || repaymentsRes.data || { total: 0, count: 0 });
    } catch (err) {
      console.error(err);
      toast.error('Failed to fetch reports data');
    } finally {
      setLoading(false);
    }
  };

  const downloadPDF = () => {
    const doc = new jsPDF();
    const currentDate = new Date().toLocaleDateString();

    // Add header
    doc.setFontSize(20);
    doc.setTextColor(102, 102, 241);
    doc.text('Harari Saving & Credit System', 14, 20);

    doc.setFontSize(16);
    doc.setTextColor(0, 0, 0);
    doc.text('Financial Reports', 14, 30);

    doc.setFontSize(10);
    doc.setTextColor(100, 100, 100);
    doc.text(`Generated on: ${currentDate}`, 14, 38);

    // Add summary section
    doc.setFontSize(14);
    doc.setTextColor(0, 0, 0);
    doc.text('Summary Statistics', 14, 50);

    const summaryData = [
      ['Total Savings', `$${savings?.total?.toLocaleString() || 0}`, `${savings?.count || 0} transactions`],
      ['Total Repayments', `$${repayments?.total?.toLocaleString() || 0}`, `${repayments?.count || 0} payments`]
    ];

    doc.autoTable({
      startY: 55,
      head: [['Category', 'Amount', 'Count']],
      body: summaryData,
      theme: 'grid',
      headStyles: { fillColor: [102, 102, 241], textColor: 255 },
      styles: { fontSize: 10 }
    });

    // Add loan distribution section
    if (loans.length > 0) {
      doc.setFontSize(14);
      doc.text('Loan Distribution by Status', 14, doc.lastAutoTable.finalY + 15);

      const loanData = loans.map(loan => [
        loan._id || 'Unknown',
        loan.count.toString(),
        `$${loan.total?.toLocaleString() || 0}`
      ]);

      doc.autoTable({
        startY: doc.lastAutoTable.finalY + 20,
        head: [['Status', 'Count', 'Total Amount']],
        body: loanData,
        theme: 'grid',
        headStyles: { fillColor: [102, 102, 241], textColor: 255 },
        styles: { fontSize: 10 }
      });
    }

    // Add footer
    const pageCount = doc.internal.getNumberOfPages();
    for (let i = 1; i <= pageCount; i++) {
      doc.setPage(i);
      doc.setFontSize(8);
      doc.setTextColor(150);
      doc.text(
        `Page ${i} of ${pageCount}`,
        doc.internal.pageSize.getWidth() / 2,
        doc.internal.pageSize.getHeight() - 10,
        { align: 'center' }
      );
    }

    doc.save(`Harari-Reports-${currentDate}.pdf`);
    toast.success('PDF downloaded successfully!');
  };

  const downloadExcel = () => {
    let csvContent = "data:text/csv;charset=utf-8,";

    // Add header
    csvContent += "Harari Saving & Credit System - Financial Reports\n";
    csvContent += `Generated on: ${new Date().toLocaleDateString()}\n\n`;

    // Summary section
    csvContent += "Summary Statistics\n";
    csvContent += "Category,Amount,Count\n";
    csvContent += `Total Savings,$${savings?.total || 0},${savings?.count || 0} transactions\n`;
    csvContent += `Total Repayments,$${repayments?.total || 0},${repayments?.count || 0} payments\n\n`;

    // Loan distribution
    if (loans.length > 0) {
      csvContent += "Loan Distribution by Status\n";
      csvContent += "Status,Count,Total Amount\n";
      loans.forEach(loan => {
        csvContent += `${loan._id || 'Unknown'},${loan.count},$${loan.total || 0}\n`;
      });
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `Harari-Reports-${new Date().toLocaleDateString()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    toast.success('Excel/CSV downloaded successfully!');
  };

  return (
    <div className="fade-in">
      <div className="flex-between mb-6">
        <div>
          <h2 className="page-title" style={{ marginBottom: '0.5rem' }}>📑 Reports & Analytics</h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', margin: 0 }}>
            View comprehensive reports and statistics
          </p>
        </div>
        <div style={{ display: 'flex', gap: '1rem' }}>
          <button
            onClick={downloadPDF}
            className="btn btn-primary"
            style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}
            disabled={loading}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
              <polyline points="7 10 12 15 17 10" />
              <line x1="12" y1="15" x2="12" y2="3" />
            </svg>
            PDF
          </button>
          <button
            onClick={downloadExcel}
            className="btn btn-primary"
            style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', background: 'var(--success)' }}
            disabled={loading}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
              <polyline points="7 10 12 15 17 10" />
              <line x1="12" y1="15" x2="12" y2="3" />
            </svg>
            Excel
          </button>
          <button
            onClick={fetchReports}
            className="btn btn-secondary"
            style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}
            disabled={loading}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className={loading ? 'rotate-icon' : ''}>
              <path d="M21.5 2v6h-6M2.5 22v-6h6M2 11.5a10 10 0 0 1 18.8-4.3M22 12.5a10 10 0 0 1-18.8 4.2" />
            </svg>
            Refresh
          </button>
        </div>
      </div>

      {loading ? (
        <div className="loading-container">
          <div className="loading-spinner"></div>
          <div style={{ color: 'var(--text-secondary)', marginTop: '1rem' }}>Loading reports...</div>
        </div>
      ) : (
        <>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '1.5rem', marginBottom: '2rem' }}>
            <div className="stats-card">
              <div className="stats-card-header">
                <div className="stats-info">
                  <div className="stats-title">Total Savings</div>
                  <div className="stats-value">${savings?.total?.toLocaleString() || 0}</div>
                  <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: '0.5rem' }}>
                    {savings?.count || 0} transactions
                  </div>
                </div>
                <div className="stats-icon" style={{
                  background: 'linear-gradient(135deg, #34d39940, #10b98180)',
                  boxShadow: '0 4px 16px #10b98140'
                }}>
                  <span style={{ fontSize: '1.5rem' }}>💰</span>
                </div>
              </div>
            </div>

            <div className="stats-card">
              <div className="stats-card-header">
                <div className="stats-info">
                  <div className="stats-title">Total Repayments</div>
                  <div className="stats-value">${repayments?.total?.toLocaleString() || 0}</div>
                  <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: '0.5rem' }}>
                    {repayments?.count || 0} payments
                  </div>
                </div>
                <div className="stats-icon" style={{
                  background: 'linear-gradient(135deg, #667eea40, #764ba280)',
                  boxShadow: '0 4px 16px #6366f140'
                }}>
                  <span style={{ fontSize: '1.5rem' }}>💳</span>
                </div>
              </div>
            </div>
          </div>

          <div className="card" style={{ padding: '1.5rem', marginBottom: '1.5rem' }}>
            <h4 style={{ margin: '0 0 1.5rem 0', color: 'var(--text-primary)', fontSize: '1.125rem', fontWeight: 600 }}>
              📊 Loan Statistics by Status
            </h4>
            {loans.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--text-secondary)' }}>
                No loan data available
              </div>
            ) : (
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '1rem' }}>
                {loans.map((loan, idx) => (
                  <div
                    key={idx}
                    style={{
                      padding: '1.25rem',
                      background: 'var(--bg-hover)',
                      borderRadius: '0.75rem',
                      border: '1px solid var(--border)',
                      transition: 'all 0.3s ease'
                    }}
                    className="hover-lift"
                  >
                    <div style={{
                      fontSize: '0.75rem',
                      color: 'var(--text-secondary)',
                      marginBottom: '0.5rem',
                      textTransform: 'uppercase',
                      letterSpacing: '0.05em'
                    }}>
                      {loan._id || 'Unknown'}
                    </div>
                    <div style={{
                      fontSize: '1.5rem',
                      fontWeight: 700,
                      color: 'var(--text-primary)',
                      marginBottom: '0.25rem'
                    }}>
                      {loan.count}
                    </div>
                    <div style={{ fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
                      ${loan.total?.toLocaleString() || 0}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="card" style={{ padding: '1.5rem' }}>
            <h4 style={{ margin: '0 0 1rem 0', color: 'var(--text-primary)', fontSize: '1.125rem', fontWeight: 600 }}>
              ℹ️ Report Information
            </h4>
            <div style={{ color: 'var(--text-secondary)', lineHeight: 1.6 }}>
              <p style={{ margin: '0 0 0.75rem 0' }}>
                • Reports are generated in real-time from the database
              </p>
              <p style={{ margin: '0 0 0.75rem 0' }}>
                • All monetary values are in USD
              </p>
              <p style={{ margin: '0 0 0.75rem 0' }}>
                • Use the export buttons to download reports as PDF or Excel format
              </p>
              <p style={{ margin: 0 }}>
                • Use the refresh button to update the statistics
              </p>
            </div>
          </div>
        </>
      )}
    </div>
  );
}
export default Reports;
